+/// SQLite LENGTH(): returns character count for text, byte count for blob,
+/// text length for numeric values, NULL for NULL.
+#[allow(clippy::cast_possible_wrap)]
+fn direct_length(value: &SqliteValue) -> SqliteValue {
+    match value {
+        SqliteValue::Null => SqliteValue::Null,
+        SqliteValue::Text(s) => SqliteValue::Integer(s.chars().count() as i64),
+        SqliteValue::Blob(b) => SqliteValue::Integer(b.len() as i64),
+        SqliteValue::Integer(_) | SqliteValue::Float(_) => {
+            SqliteValue::Integer(value.to_text().len() as i64)
+        }
+    }
+}
+
+/// SQLite UPPER(): ASCII uppercase after coercing non-NULL values to text.
+fn direct_upper(value: &SqliteValue) -> SqliteValue {
+    match value {
+        SqliteValue::Null => SqliteValue::Null,
+        _ => SqliteValue::Text(value.to_text().to_ascii_uppercase().into()),
+    }
+}
