+/// SQLite SUBSTR(str, start [, length]): 1-based indexing, negative start
+/// counts from end.  NULL input → NULL.
+#[allow(
+    clippy::cast_possible_truncation,
+    clippy::cast_sign_loss,
+    clippy::cast_possible_wrap
+)]
+fn direct_substr(value: &SqliteValue, start: i64, length: Option<i64>) -> SqliteValue {
+    if value.is_null() {
+        return SqliteValue::Null;
+    }
+    let text = sqlite_value_to_text(value);
+    let chars: Vec<char> = text.chars().collect();
+    let n = chars.len() as i64;
+    let p2 = match start.cmp(&0) {
+        std::cmp::Ordering::Less => n + 1 + start,
+        std::cmp::Ordering::Equal => 0,
+        std::cmp::Ordering::Greater => start,
+    };
+    match length {
+        Some(length) => {
+            let (y, z) = if length < 0 {
+                (p2 + length, p2)
+            } else {
+                (p2, p2 + length)
+            };
+            let start = (y.max(1) - 1) as usize;
+            let end = ((z - 1).max(0) as usize).min(chars.len());
+            let start = start.min(chars.len());
+            if start < end {
+                SqliteValue::Text(chars[start..end].iter().collect::<String>().into())
+            } else {
+                SqliteValue::Text(String::new().into())
             }
         }
+        None => {
+            let idx = ((p2.max(1) - 1) as usize).min(chars.len());
+            SqliteValue::Text(chars[idx..].iter().collect::<String>().into())
+        }
     }
 }

